pub struct ProgramSimulation {
    model: Box<dyn Model>,
    messages: Vec<Msg>,
    views: Vec<String>,
}

impl ProgramSimulation {
    /// Run simulation with recorded inputs
    pub fn run(&mut self, inputs: Vec<Msg>) {
        for msg in inputs {
            self.messages.push(msg.clone());
            let (new_model, cmd) = self.model.update(msg);
            self.model = new_model;
            let view = self.model.view();
            self.views.push(view);

            ctx.log("view_after_update", &view);
        }
    }

    /// Compare views against expected
    pub fn verify(&self, expected_views: &[String]) -> TestResult;
}
