## Simulation Framework

```rust
/// Program simulation for testing without real terminal
pub struct ProgramSimulator {
    model: Box<dyn Model>,
    input_queue: VecDeque<Msg>,
    output_views: Vec<String>,
    commands_executed: Vec<String>,
}

impl ProgramSimulator {
    pub fn new(model: impl Model) -> Self { ... }

    /// Queue an input message
    pub fn send(&mut self, msg: Msg) {
        self.input_queue.push_back(msg);
    }

    /// Run one update cycle
    pub fn step(&mut self) -> Option<Cmd> {
        if let Some(msg) = self.input_queue.pop_front() {
            let (new_model, cmd) = self.model.update(msg);
            self.model = new_model;
            self.output_views.push(self.model.view());
            return cmd;
        }
        None
    }

    /// Run until Quit or max steps
    pub fn run_until_quit(&mut self, max_steps: usize) -> &dyn Model {
        for _ in 0..max_steps {
            if let Some(Quit) = self.step() {
                break;
            }
        }
        &*self.model
    }
}
